 142→// ---------------------------------------------------------------------------
 143→// SSE Stream Helpers
 144→// ---------------------------------------------------------------------------
 145→
 146→export type SSEEvent = {
 147→  event?: string;
 148→  data: string;
 149→};
 150→
 151→/**
 152→ * Collect all SSE events from a streaming proxy response.
 153→ */
 154→export async function collectProxySSEEvents(response: Response): Promise<SSEEvent[]> {
 155→  if (!response.body) {
 156→    throw new Error("No response body for SSE collection");
 157→  }
 158→
 159→  const reader = response.body.getReader();
 160→  const decoder = new TextDecoder();
 161→  const events: SSEEvent[] = [];
 162→  let buffer = "";
 163→
 164→  try {
 165→    while (true) {
 166→      const { done, value } = await reader.read();
 167→      if (done) break;
 168→
 169→      buffer += decoder.decode(value, { stream: true });
 170→      const segments = buffer.split("\n\n");
 171→      buffer = segments.pop() ?? "";
 172→
 173→      for (const segment of segments) {
 174→        const lines = segment.split("\n");
 175→        let eventType: string | undefined;
 176→        let dataLine: string | undefined;
 177→
 178→        for (const line of lines) {
 179→          if (line.startsWith("event: ")) {
 180→            eventType = line.slice(7);
 181→          } else if (line.startsWith("data: ")) {
 182→            dataLine = line.slice(6);
 183→          }
 184→        }
 185→
 186→        if (dataLine !== undefined) {
 187→          events.push({ event: eventType, data: dataLine });
 188→        }
 189→      }
 190→    }
 191→  } finally {
 192→    reader.releaseLock();
 193→  }
 194→
 195→  return events;
 196→}
