 442→
 443→  // Link session directly on trace record (schema: session TYPE option<record<agent_session>>)
 444→  if (options.sessionId) {
 445→    traceContent.session = new RecordId("agent_session", options.sessionId);
 446→  }
 447→
 448→  await surreal.query(`CREATE $trace CONTENT $content;`, {
 449→    trace: traceRecord,
 450→    content: traceContent,
 451→  });
 452→
 453→  // Create workspace edge
 454→  await surreal.query(
 455→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
 456→    { trace: traceRecord, workspace: workspaceRecord },
