 484→/**
 485→ * Create a model access policy for the proxy.
 486→ */
 487→export async function createModelAccessPolicy(
 488→  surreal: Surreal,
 489→  workspaceId: string,
 490→  options: {
 491→    policyId: string;
 492→    agentType: string;
 493→    allowedModels: string[];
 494→    status?: string;
 495→  },
 496→): Promise<string> {
 497→  const policyRecord = new RecordId("policy", options.policyId);
 498→  const workspaceRecord = new RecordId("workspace", workspaceId);
 499→
 500→  await surreal.query(`CREATE $policy CONTENT $content;`, {
 501→    policy: policyRecord,
 502→    content: {
 503→      title: `Model Access: ${options.agentType}`,
 504→      description: `Controls which models ${options.agentType} can use`,
 505→      status: options.status ?? "active",
 506→      version: 1,
 507→      workspace: workspaceRecord,
 508→      rules: [{
 509→        id: "model_access",
 510→        condition: { field: "agent_type", operator: "eq", value: options.agentType },
 511→        effect: "allow",
 512→        priority: 50,
 513→        params: { allowed_models: options.allowedModels },
 514→      }],
 515→      created_at: new Date(),
 516→    },
