1098→/**
1099→ * Seed an LLM trace with response content in the FLEXIBLE output field.
1100→ * Used for Observer per-trace analysis testing.
1101→ */
1102→export async function seedLlmTraceWithContent(
1103→  surreal: Surreal,
1104→  traceId: string,
1105→  options: {
1106→    model: string;
1107→    workspaceId: string;
1108→    sessionId?: string;
1109→    conversationId?: string;
1110→    responseText: string;
1111→    stopReason?: string;
1112→    inputTokens?: number;
1113→    outputTokens?: number;
1114→    costUsd?: number;
1115→  },
1116→): Promise<string> {
1117→  const traceRecord = new RecordId("trace", traceId);
1118→  const workspaceRecord = new RecordId("workspace", options.workspaceId);
1119→
1120→  // Ensure a test identity exists for the actor field (required by trace schema)
1121→  const actorId = `proxy-test-actor-${options.workspaceId}`;
1122→  const actorRecord = new RecordId("identity", actorId);
1123→  await surreal.query(
1124→    `CREATE $actor CONTENT { name: "proxy-test-system", type: "system", workspace: $ws, created_at: time::now() };`,
1125→    { actor: actorRecord, ws: workspaceRecord },
1126→  ).catch(() => undefined); // Ignore if already exists
1127→
1128→  const input: Record<string, unknown> = {};
1129→  if (options.conversationId) {
1130→    input.conversation = new RecordId("conversation", options.conversationId);
1131→  }
1132→
1133→  const output: Record<string, unknown> = {
1134→    content: [{ type: "text", text: options.responseText }],
1135→    stop_reason: options.stopReason ?? "end_turn",
1136→  };
1137→
1138→  await surreal.query(`CREATE $trace CONTENT $content;`, {
1139→    trace: traceRecord,
1140→    content: {
1141→      type: "llm_call",
1142→      model: options.model,
1143→      actor: actorRecord,
1144→      workspace: workspaceRecord,
1145→      input_tokens: options.inputTokens ?? 100,
1146→      output_tokens: options.outputTokens ?? 50,
1147→      cache_read_tokens: 0,
1148→      cache_creation_tokens: 0,
1149→      cost_usd: options.costUsd ?? 0.001,
1150→      latency_ms: 500,
1151→      stop_reason: options.stopReason ?? "end_turn",
1152→      input,
1153→      output,
1154→      created_at: new Date(),
1155→    },
1156→  });
1157→
1158→  // Create workspace edge
1159→  await surreal.query(
1160→    `RELATE $trace->scoped_to->$workspace SET created_at = time::now();`,
1161→    { trace: traceRecord, workspace: workspaceRecord },
1162→  );
1163→
1164→  // Link to session: set session field on trace AND create invoked edge
1165→  if (options.sessionId) {
1166→    const sessionRecord = new RecordId("agent_session", options.sessionId);
1167→    await surreal.query(
1168→      `UPDATE $trace SET session = $sess;`,
1169→      { trace: traceRecord, sess: sessionRecord },
1170→    );
1171→    await surreal.query(
1172→      `RELATE $sess->invoked->$trace SET created_at = time::now();`,
1173→      { trace: traceRecord, sess: sessionRecord },
1174→    );
1175→  }
1176→
1177→  return traceId;
1178→}
