1187→export async function triggerCoherenceScan(
1188→  baseUrl: string,
1189→  workspaceId: string,
1190→): Promise<Response> {
1191→  return fetch(
1192→    `${baseUrl}/api/observe/scan/${workspaceId}`,
1193→    { method: "POST" },
1194→  );
1195→}
