/**
 * Query traces for a project within a date range.
 */
export async function queryTracesByProject(
  baseUrl: string,
  workspaceId: string,
  projectId: string,
  startDate: string,
  endDate: string,
): Promise<Response> {
  return fetch(
    `${baseUrl}/api/workspaces/${workspaceId}/proxy/traces?project=${projectId}&start=${startDate}&end=${endDate}`,
    { method: "GET" },
